import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login(formData.email, formData.password);
      toast.success('Login realizado com sucesso!');
    } catch (error) {
      const errorMessage = error.response?.data?.message || 'Erro ao fazer login. Verifique suas credenciais.';
      setError(errorMessage);
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2,
        // Fundo animado CSS que simula o vídeo
        background: `
          radial-gradient(circle at 20% 20%, rgba(0, 100, 200, 0.1) 0%, transparent 40%),
          radial-gradient(circle at 80% 80%, rgba(100, 0, 200, 0.1) 0%, transparent 40%),
          radial-gradient(circle at 40% 60%, rgba(0, 200, 100, 0.08) 0%, transparent 40%),
          linear-gradient(45deg, #000 0%, #001122 25%, #002244 50%, #001122 75%, #000 100%)
        `,
        animation: 'backgroundShift 20s ease-in-out infinite',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: `
            linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.02) 50%, transparent 100%),
            linear-gradient(0deg, transparent 0%, rgba(255,255,255,0.01) 50%, transparent 100%)
          `,
          animation: 'scanlines 8s linear infinite',
          pointerEvents: 'none'
        },
        '&::after': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: `
            radial-gradient(circle at 50% 50%, transparent 30%, rgba(0,0,0,0.2) 70%),
            repeating-linear-gradient(
              0deg,
              transparent,
              transparent 2px,
              rgba(255,255,255,0.005) 2px,
              rgba(255,255,255,0.005) 4px
            )
          `,
          animation: 'pulse 15s ease-in-out infinite',
          pointerEvents: 'none'
        },
        '@keyframes backgroundShift': {
          '0%, 100%': {
            backgroundPosition: '0% 0%, 100% 100%, 0% 100%, 0% 0%'
          },
          '25%': {
            backgroundPosition: '100% 0%, 0% 100%, 100% 0%, 25% 25%'
          },
          '50%': {
            backgroundPosition: '100% 100%, 0% 0%, 50% 50%, 50% 50%'
          },
          '75%': {
            backgroundPosition: '0% 100%, 100% 0%, 0% 0%, 75% 75%'
          }
        },
        '@keyframes scanlines': {
          '0%': {
            transform: 'translateX(-100%)'
          },
          '100%': {
            transform: 'translateX(100%)'
          }
        },
        '@keyframes pulse': {
          '0%, 100%': {
            opacity: 0.5
          },
          '50%': {
            opacity: 0.8
          }
        }
      }}
    >
      {/* Overlay escuro */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.4)',
          zIndex: 1
        }}
      />

      <Container component="main" maxWidth="xs" sx={{ zIndex: 2, position: 'relative' }}>
        <Paper
          elevation={24}
          sx={{
            padding: 4,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            backgroundColor: 'rgba(0, 0, 0, 0.85)',
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(255, 255, 255, 0.1)',
            borderRadius: 2
          }}
        >
          <Typography
            variant="h4"
            component="h1"
            gutterBottom
            sx={{
              color: '#C0C0C0',
              fontWeight: 'bold',
              textAlign: 'center',
              mb: 3
            }}
          >
            Nautilus Automação
          </Typography>

          {error && (
            <Alert severity="error" sx={{ width: '100%', mb: 2 }}>
              {error}
            </Alert>
          )}

          <Box component="form" onSubmit={handleSubmit} sx={{ width: '100%' }}>
            <TextField
              margin="normal"
              required
              fullWidth
              id="email"
              label="Email"
              name="email"
              type="email"
              autoComplete="email"
              autoFocus
              value={formData.email}
              onChange={handleChange}
              disabled={loading}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                style: { color: '#C0C0C0' }
              }}
              InputLabelProps={{
                style: { color: '#C0C0C0' }
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  '& fieldset': {
                    borderColor: '#C0C0C0'
                  },
                  '&:hover fieldset': {
                    borderColor: '#C0C0C0'
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: '#C0C0C0'
                  }
                }
              }}
            />

            <TextField
              margin="normal"
              required
              fullWidth
              name="password"
              label="Senha"
              type={showPassword ? 'text' : 'password'}
              id="password"
              autoComplete="current-password"
              value={formData.password}
              onChange={handleChange}
              disabled={loading}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      aria-label="toggle password visibility"
                      onClick={togglePasswordVisibility}
                      edge="end"
                      sx={{ color: '#C0C0C0' }}
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
                style: { color: '#C0C0C0' }
              }}
              InputLabelProps={{
                style: { color: '#C0C0C0' }
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  '& fieldset': {
                    borderColor: '#C0C0C0'
                  },
                  '&:hover fieldset': {
                    borderColor: '#C0C0C0'
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: '#C0C0C0'
                  }
                }
              }}
            />

            <Button
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading}
              sx={{
                mt: 3,
                mb: 2,
                backgroundColor: 'rgba(0, 0, 0, 0.8)',
                color: '#C0C0C0',
                border: '1px solid #C0C0C0',
                '&:hover': {
                  backgroundColor: 'rgba(0, 0, 0, 0.9)',
                  borderColor: '#C0C0C0'
                },
                '&:disabled': {
                  backgroundColor: 'rgba(0, 0, 0, 0.6)',
                  color: 'rgba(192, 192, 192, 0.5)'
                }
              }}
            >
              {loading ? <CircularProgress size={24} sx={{ color: '#C0C0C0' }} /> : 'Acessar'}
            </Button>

